  if (!Number.isSafeInteger(index) || index < 0 || index >= grid.width * grid.height) {
    throw new RangeError(`index ${index} out of bounds`);
  }

  return {
    x: index % grid.width,
    y: Math.floor(index / grid.width),
  };
};

