215	        })
216	      ]);
217	    }
218	
219	    const events = [
220	      runEvent(state.run.turn, "run_action_resolved", {
221	        actionKind: action.kind
222	      }),
223	      ...resolved.events
224	    ];
225	
226	    return success(appendRunLog(resolved.state, events), events);
227	  }
228	
229	  if (
